clear all; close all; clc;% --- Constants ---C = 1.35;beta = 4.0;alpha = [-0.024, 0.0216, -0.0012, 0.12];dt = 0.005;               % FIXED TIME STEP (5ms)t_end = 300;t = 0:dt:t_end;n_steps = length(t);HR_bpm = 95;Gamma_t = 0.08804 * HR_bpm  - 0.06754;H_values = [3.0, 2.729, 2.164];titles = {'Normal Rhythm', 'Quasiperiodicity', 'VF'};figure('Name', 'Fixed-Step Tustin Implicit Solver (dt=0.005)');for h_idx = 1:3    H = H_values(h_idx);    % Initialize States    x = zeros(4, n_steps);    x(:,1) = [0.0; 0.0; 0.1; 0.0];; % Initial Condition x0    % --- Main Simulation Loop (The "Outer" Time Step) ---    for n = 1:n_steps-1        xp = x(:, n);      % Previous state        xn = xp;           % Initial guess for current state (n+1)        % --- Newton-Raphson Loop (The "Inner" Implicit Solver) ---        for iter = 1:4            % 1. Calculate f(xn) and f(xp)            f_n = Gamma_t * [xn(1) - xn(2) - C*xn(1)*xn(2) - xn(1)*xn(2)^2;                   H*xn(1) - 3*xn(2) + C*xn(1)*xn(2) + xn(1)*xn(2)^2 + beta*(xn(4) - xn(2));                   xn(3) - xn(4) - C*xn(3)*xn(4) - xn(3)*xn(4)^2;                   H*xn(3) - 3*xn(4) + C*xn(3)*xn(4) + xn(3)*xn(4)^2 + 2*beta*(xn(2) - xn(4))];            f_p = Gamma_t * [xp(1) - xp(2) - C*xp(1)*xp(2) - xp(1)*xp(2)^2;                   H*xp(1) - 3*xp(2) + C*xp(1)*xp(2) + xp(1)*xp(2)^2 + beta*(xp(4) - xp(2));                   xp(3) - xp(4) - C*xp(3)*xp(4) - xp(3)*xp(4)^2;                   H*xp(3) - 3*xp(4) + C*xp(3)*xp(4) + xp(3)*xp(4)^2 + 2*beta*(xp(2) - xp(4))];            % 2. Tustin Residual R            R = xn - xp - (dt/2) * (f_n + f_p);            % 3. Jacobian Matrix J (Evaluated at xn)            % This is exactly what SymPy generated for your C code            J = eye(4) - (dt/2) * Gamma_t * [ ...                (1 - C*xn(2) - xn(2)^2),                 (-1 - C*xn(1) - 2*xn(1)*xn(2)), 0, 0;                (H + C*xn(2) + xn(2)^2),                 (-3 + C*xn(1) + 2*xn(1)*xn(2) - beta), 0, beta;                0, 0,                                    (1 - C*xn(4) - xn(4)^2), (-1 - C*xn(3) - 2*xn(3)*xn(4));                0, 2*beta,                               (H + C*xn(4) + xn(4)^2), (-3 + C*xn(3) + 2*xn(3)*xn(4) - 2*beta)];            % 4. Newton Update: x_new = x_old - J\R            dx = J\R;            xn = xn - dx;            if norm(dx) < 1e-8, break; end % Convergence check        end        x(:, n+1) = xn; % Store finalized state    end    % 5. Apply ECG Weights    ECG = alpha * x;    % Plotting (Zooming into 195s to 200s to match Paper)    subplot(3, 1, h_idx);    idx_zoom = (t >= 195 & t <= 200);    plot(t(idx_zoom), ECG(idx_zoom), 'k', 'LineWidth', 1.5);    title([titles{h_idx}, ' (Fixed-Step Tustin, dt=0.005)']);    ylabel('ECG \xi(t)'); grid on;endxlabel('Time (s)');